"use client";

import * as React from "react";
import dynamic from "next/dynamic";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

type OrbState = "idle" | "listening" | "speaking" | "thinking";

interface OrbProps
  extends
    Omit<React.ComponentProps<"div">, "children">,
    VariantProps<typeof orbVariants> {
  /** Current animation state. Default: "idle" */
  state?: OrbState;
  /** Orb color. Default: "hsl(var(--primary))" */
  color?: string;
  /** Force CSS-only rendering (no WebGL). Default: false */
  forceCSS?: boolean;
  /** Override distortion factor (0-1). */
  distort?: number;
  /** Override animation speed multiplier. */
  speed?: number;
}

// =============================================================================
// VARIANTS
// =============================================================================

const orbVariants = cva(
  "relative inline-flex items-center justify-center overflow-hidden",
  {
    variants: {
      size: {
        sm: "h-20 w-20",
        md: "h-30 w-30",
        lg: "h-40 w-40",
      },
    },
    defaultVariants: {
      size: "md",
    },
  }
);

// =============================================================================
// STATE PRESETS
// =============================================================================

const statePresets: Record<OrbState, { speed: number; distort: number }> = {
  idle: { speed: 0.5, distort: 0.3 },
  listening: { speed: 1.5, distort: 0.4 },
  speaking: { speed: 3, distort: 0.6 },
  thinking: { speed: 1, distort: 0.5 },
};

// =============================================================================
// CSS-ONLY FALLBACK ORB
// =============================================================================

const cssStateMap: Record<
  OrbState,
  { duration: string; scale: string; shadow: string }
> = {
  idle: {
    duration: "4s",
    scale: "scale(1) scale(1.03)",
    shadow: "0 0 40px 8px",
  },
  listening: {
    duration: "2s",
    scale: "scale(1) scale(1.06)",
    shadow: "0 0 50px 12px",
  },
  speaking: {
    duration: "0.8s",
    scale: "scale(1) scale(1.1)",
    shadow: "0 0 60px 16px",
  },
  thinking: {
    duration: "3s",
    scale: "scale(1) scale(1.05)",
    shadow: "0 0 45px 10px",
  },
};

function CSSOrb({
  state = "idle",
  color = "hsl(var(--primary))",
  className,
  size,
  ...props
}: Omit<OrbProps, "forceCSS" | "distort" | "speed">) {
  const preset = cssStateMap[state];
  const keyframeName = `orb-pulse-${state}`;

  return (
    <div
      data-slot="orb"
      data-state={state}
      className={cn(orbVariants({ size }), className)}
      {...props}
    >
      <div
        className="absolute inset-0 rounded-full"
        style={{
          background: `radial-gradient(circle at 35% 35%, color-mix(in srgb, ${color} 80%, white 20%), ${color}, color-mix(in srgb, ${color} 60%, black 40%))`,
          boxShadow: `${preset.shadow} color-mix(in srgb, ${color} 40%, transparent)`,
          animation: `${keyframeName} ${preset.duration} ease-in-out infinite alternate`,
        }}
      />
      <style
        dangerouslySetInnerHTML={{
          __html: `
            @keyframes ${keyframeName} {
              from { transform: scale(1); opacity: 0.9; }
              to { transform: ${preset.scale}; opacity: 1; }
            }
          `,
        }}
      />
    </div>
  );
}

CSSOrb.displayName = "CSSOrb";

// =============================================================================
// THREE.JS ORB (dynamically imported for SSR safety)
// =============================================================================

interface ThreeOrbSceneProps {
  state: OrbState;
  color: string;
  distort?: number;
  speed?: number;
}

// Lazily-initialized R3F module cache — only populated on first client render
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let r3fCache: any = null;
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let dreiCache: any = null;

function getR3F(): typeof import("@react-three/fiber") {
  if (!r3fCache) r3fCache = require("@react-three/fiber");
  return r3fCache;
}

function getDrei(): typeof import("@react-three/drei") {
  if (!dreiCache) dreiCache = require("@react-three/drei");
  return dreiCache;
}

// Stable module-level component — no re-mount on parent re-render
function AnimatedOrbMesh({
  color,
  targetSpeed,
  targetDistort,
}: {
  color: string;
  targetSpeed: number;
  targetDistort: number;
}) {
  const { useFrame } = getR3F();
  const { MeshDistortMaterial, Sphere } = getDrei();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const materialRef = React.useRef<any>(null);
  const currentSpeed = React.useRef(targetSpeed);
  const currentDistort = React.useRef(targetDistort);

  useFrame(() => {
    // Smooth lerp transitions between states
    currentSpeed.current += (targetSpeed - currentSpeed.current) * 0.05;
    currentDistort.current += (targetDistort - currentDistort.current) * 0.05;

    if (materialRef.current) {
      materialRef.current.speed = currentSpeed.current;
      materialRef.current.distort = currentDistort.current;
    }
  });

  return (
    <Sphere args={[1, 64, 64]}>
      <MeshDistortMaterial
        ref={materialRef}
        color={color}
        roughness={0.2}
        metalness={0.1}
        speed={targetSpeed}
        distort={targetDistort}
      />
    </Sphere>
  );
}

AnimatedOrbMesh.displayName = "AnimatedOrbMesh";

function ThreeOrbScene({ state, color, distort, speed }: ThreeOrbSceneProps) {
  const { Canvas } = getR3F();

  const preset = statePresets[state];
  const targetSpeed = speed ?? preset.speed;
  const targetDistort = distort ?? preset.distort;

  return (
    <Canvas
      dpr={[1, 2]}
      camera={{ position: [0, 0, 3], fov: 45 }}
      style={{ background: "transparent" }}
      gl={{ alpha: true, antialias: true }}
    >
      <ambientLight intensity={0.6} />
      <pointLight position={[10, 10, 10]} intensity={1} />
      <pointLight position={[-10, -5, -10]} intensity={0.4} />
      <AnimatedOrbMesh
        color={color}
        targetSpeed={targetSpeed}
        targetDistort={targetDistort}
      />
    </Canvas>
  );
}

// Dynamic import wrapper for SSR safety (same pattern as maps-showcase.tsx)
const DynamicThreeOrb = dynamic(
  () => Promise.resolve({ default: ThreeOrbScene }),
  { ssr: false }
);

// =============================================================================
// MAIN COMPONENT
// =============================================================================

const Orb = React.forwardRef<HTMLDivElement, OrbProps>(
  (
    {
      state = "idle",
      color = "hsl(var(--primary))",
      forceCSS = false,
      distort,
      speed,
      size,
      className,
      ...props
    },
    ref
  ) => {
    if (forceCSS) {
      return (
        <CSSOrb
          ref={ref}
          state={state}
          color={color}
          size={size}
          className={className}
          {...props}
        />
      );
    }

    return (
      <div
        ref={ref}
        data-slot="orb"
        data-state={state}
        className={cn(orbVariants({ size }), className)}
        {...props}
      >
        <DynamicThreeOrb
          state={state}
          color={color}
          distort={distort}
          speed={speed}
        />
      </div>
    );
  }
);

Orb.displayName = "Orb";

export { Orb, CSSOrb, type OrbProps, type OrbState };
